fun solve(edges: Array<Array<Long>>, online: Array<Boolean>, k: Long): Long {
    val n = online.size
    val graph = arrayOf<MutableList<Pair<Long, Long>>>(n)
    for (i in edges.indices) {
        val u = edges[i][0]
        val v = edges[i][1]
        val cost = edges[i][2]
        graph[u].add(Pair(v, cost))
    }

    val maxScore = Long.MIN_VALUE
    val dist = arrayOf<Long>(n.toDouble()).toLongArray()
    val pq = PriorityQueue<Pair<Long, Long>>(Comparator { a, b -> a.second.compareTo(b.second) })

    dist[0] = 0
    pq.add(Pair(0.toDouble(), 0.toDouble()))

    while (pq.isNotEmpty()) {
        val (currentNode, currentMin) = pq.remove()
        if (currentNode == n - 1) {
            return currentMin
        }
        if (currentMin > k) continue
        for (neighbor in graph[currentNode]) {
            val nextNode = neighbor.first
            val nextCost = neighbor.second
            if (online[nextNode] && currentMin + nextCost <= k) {
                val newMin = min(currentMin, nextCost)
                if (dist[nextNode] == Long.MIN_VALUE || newMin > dist[nextNode]) {
                    dist[nextNode] = newMin
                    pq.add(Pair(nextNode.toDouble(), newMin))
                }
            }
        }
    }

    return -1
}
